<?phpdeclare(strict_types=1);namespace api\task;use api\Loader;use pocketmine\level\particle\{FloatingTextParticle, GenericParticle, Particle};use pocketmine\math\Vector3;use pocketmine\level\Level;use pocketmine\level\Position;use pocketmine\block\Block;use pocketmine\scheduler\Task;class RemoveBlockTask extends \pocketmine\scheduler\Task {    private $pos;    private $level;    public function __construct(Vector3 $pos, Level $level) {        $this->pos = $pos;        $this->level = $level;    }    public function onRun($currentTick) {        $block = $this->level->getBlock($this->pos);        if($block->getId() !== Block::AIR) {            $this->level->setBlock($this->pos, Block::get(Block::AIR));        }    }}